// AlertPanel.tsx — SCE Design System
// Collapsible container for AlertCard items.
// Manages per-card dismiss and syncs the count in the header.

import React, { useState } from 'react';
import { Notification, ChevronDown } from '@carbon/icons-react';
import { AlertCard, AlertCardProps } from './AlertCard';
import styles from './AlertPanel.module.css';

interface AlertPanelProps {
  alerts:       AlertCardProps[];  // initial list — typically from /api/v1/alerts
  defaultOpen?: boolean;           // panel starts expanded (default: true)
}

export const AlertPanel: React.FC<AlertPanelProps> = ({
  alerts: initialAlerts,
  defaultOpen = true,
}) => {
  const [open,   setOpen]   = useState(defaultOpen);
  const [alerts, setAlerts] = useState(initialAlerts);

  const dismiss = (index: number) =>
    setAlerts(prev => prev.filter((_, i) => i !== index));

  // Renders nothing when all cards are dismissed
  if (alerts.length === 0) return null;

  return (
    <div className={styles.panel}>
      <button
        className={styles.header}
        onClick={() => setOpen(v => !v)}
        aria-expanded={open}
        aria-controls="alert-panel-list"
      >
        <span className={styles.headerLeft}>
          <Notification size={20} aria-hidden="true" />
          <span className={styles.headerTitle}>
            Alerts ({alerts.length})
          </span>
        </span>
        <ChevronDown
          size={20}
          aria-hidden="true"
          className={[styles.chevron, open ? styles.chevronOpen : ''].join(' ')}
        />
      </button>

      <div
        id="alert-panel-list"
        className={styles.list}
        style={{ display: open ? 'flex' : 'none' }}
        aria-hidden={!open}
      >
        {alerts.map((alert, i) => (
          <AlertCard
            key={alert.variant + '-' + i}
            {...alert}
            dismissible
            collapsible
            onDismiss={() => dismiss(i)}
          />
        ))}
      </div>
    </div>
  );
};

// AlertCard.tsx — SCE Design System
// Single alert card. variant drives color, icon, and ARIA live region.
// Requires: @carbon/icons-react

import React, { useState } from 'react';
import {
  ErrorFilled, InformationFilled, CheckmarkFilled,
  WarningFilled, Notification, Close, ChevronDown,
} from '@carbon/icons-react';
import styles from './AlertCard.module.css';

export type AlertVariant = 'error' | 'warn' | 'inform' | 'success' | 'pewter';

export interface AlertCardProps {
  variant:      AlertVariant;       // drives color, icon, ARIA live region
  title:        string;             // bold heading (required)
  meta?:        string;             // e.g. "April 28, 2026  ·  9:15 AM"
  body?:        React.ReactNode;    // JSX-safe body copy
  dismissible?: boolean;            // show × button (default: false)
  onDismiss?:   () => void;         // fires after fade-out animation (~220ms)
  action?:      { label: string; onClick: () => void };  // optional CTA
  collapsible?: boolean;            // body collapses to 1 line (default: false)
}

// Carbon icon per variant
const ICONS: Record<AlertVariant, React.ReactNode> = {
  error:   <ErrorFilled        size={20} />,
  warn:    <WarningFilled      size={20} />,
  inform:  <InformationFilled  size={20} />,
  success: <CheckmarkFilled    size={20} />,
  pewter:  <Notification       size={20} />,
};

// error + warn interrupt the user; others politely update
const ARIA_LIVE: Record<AlertVariant, 'assertive' | 'polite'> = {
  error: 'assertive', warn: 'assertive',
  inform: 'polite', success: 'polite', pewter: 'polite',
};

export const AlertCard: React.FC<AlertCardProps> = ({
  variant, title, meta, body,
  dismissible = false, onDismiss,
  action, collapsible = false,
}) => {
  const [expanded,   setExpanded]   = useState(!collapsible);
  const [dismissing, setDismissing] = useState(false);

  const handleDismiss = () => {
    setDismissing(true);
    setTimeout(() => onDismiss?.(), 220); // match CSS transition-duration
  };

  const isUrgent = variant === 'error' || variant === 'warn';

  return (
    <div
      className={[styles.card, styles[variant], dismissing ? styles.dismissing : ''].join(' ')}
      role={isUrgent ? 'alert' : 'status'}
      aria-live={ARIA_LIVE[variant]}
      aria-atomic="true"
    >
      {/* Variant icon */}
      <span className={styles.icon} aria-hidden="true">{ICONS[variant]}</span>

      {/* Title */}
      <p className={styles.title}>{title}</p>

      {/* Dismiss — CSS applies 44×44px tap zone on mobile (WCAG 2.5.5) */}
      {dismissible && (
        <button
          className={styles.dismiss}
          onClick={handleDismiss}
          aria-label={'Dismiss: ' + title}
        >
          <Close size={16} />
        </button>
      )}

      {/* Timestamp / meta */}
      {meta && <p className={styles.meta}>{meta}</p>}

      {/* Body */}
      {body && (
        <div className={[styles.body, collapsible && !expanded ? styles.collapsed : ''].join(' ')}>
          {body}
          {/* CTA — inline on desktop, full-width via CSS @media on mobile */}
          {action && !collapsible && (
            <a href="#" className={styles.action}
               onClick={(e) => { e.preventDefault(); action.onClick(); }}>
              {action.label}
            </a>
          )}
        </div>
      )}

      {/* Read More / Read Less toggle */}
      {collapsible && (
        <button
          className={[styles.readMore, expanded ? styles.expanded : ''].join(' ')}
          onClick={() => setExpanded(v => !v)}
          aria-expanded={expanded}
          aria-label={(expanded ? 'Read less' : 'Read more') + ' about ' + title}
        >
          {expanded ? 'Read Less' : 'Read More'} <ChevronDown size={14} />
        </button>
      )}
    </div>
  );
};

