// Button.tsx — SCE Design System
// Three variants × four sizes. Pairs with @carbon/icons-react for leading icons.
//
// Size guidance:
//   sm  (h: 36px) — desktop only; below WCAG 2.5.5 44px touch minimum
//   md  (h: 44px) — default; safe on all platforms
//   lg  (h: 52px) — prominent page actions
//   xl  (h: 60px) — hero / landing CTAs

import React from 'react';
import styles from './Button.module.css';

export type ButtonVariant = 'primary' | 'secondary' | 'text';
export type ButtonSize    = 'sm' | 'md' | 'lg' | 'xl';

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  /** Visual emphasis. primary = yellow fill, secondary = outlined, text = inline link. */
  variant?:   ButtonVariant;
  /** Touch-target height. sm is desktop-only. Default: 'md' */
  size?:      ButtonSize;
  /** Stretch to 100% container width. Recommended for mobile primary actions. */
  fullWidth?: boolean;
  /** Leading icon — pass a @carbon/icons-react component at size={16}. */
  icon?:      React.ReactNode;
  /** Show spinner, disable interaction, set aria-busy. Use during async ops. */
  loading?:   boolean;
}

export const Button: React.FC<ButtonProps> = ({
  variant   = 'primary',
  size      = 'md',
  fullWidth = false,
  icon,
  loading   = false,
  disabled,
  children,
  className,
  ...rest
}) => {
  const cls = [
    styles.btn,
    styles[variant],
    styles[size],
    fullWidth           ? styles.full     : '',
    disabled || loading ? styles.disabled : '',
    className           ?? '',
  ].filter(Boolean).join(' ');

  return (
    <button
      {...rest}
      className={cls}
      disabled={disabled || loading}
      aria-busy={loading || undefined}
    >
      {loading  && <span className={styles.spinner} aria-hidden="true" />}
      {!loading && icon && (
        <span className={styles.icon} aria-hidden="true">{icon}</span>
      )}
      {children}
    </button>
  );
};

// Usage examples — Button
