// C24cCard.tsx — SCE Design System
// Mobile-only white card: photo top, red brand icon + bold title + description, launch icon.
// Fixed width: 323px (360px column minus 2×16px gutters — 1px border each side).

import React from 'react';
import styles from './C24cCard.module.css';

export interface C24cCardProps {
  src:          string;          // Photo URL
  alt?:         string;          // Alt text (decorative by default)
  icon:         React.ReactNode; // Carbon icon, 16×16, renders in red square
  title:        string;
  description?: string;
  href?:        string;          // Opens via launch icon
  onClick?:     () => void;
}

export const C24cCard: React.FC<C24cCardProps> = ({
  src, alt = '', icon, title, description, href, onClick,
}) => {
  const El = href ? 'a' : 'div';
  const linkProps = href ? { href, target: '_blank', rel: 'noopener noreferrer' } : {};

  return (
    <El className={styles.card} onClick={onClick} {...linkProps}>
      <div className={styles.photoWrap}>
        <img className={styles.photo} src={src} alt={alt} aria-hidden={!alt || undefined} />
      </div>
      <div className={styles.content}>
        <div className={styles.header}>
          <div className={styles.icon} aria-hidden="true">{icon}</div>
          <div className={styles.titleRow}>
            <p className={styles.title}>{title}</p>
            {href && (
              <div className={styles.launch} aria-hidden="true">
                {/* Carbon: Launch */}
                <svg width={16} height={16} viewBox="0 0 32 32" fill="currentColor">
                  <path d="M26,28H6a2,2,0,0,1-2-2V6A2,2,0,0,1,6,4H16V6H6V26H26V16h2V26A2,2,0,0,1,26,28Z"/>
                  <polygon points="20 2 20 4 26.586 4 18 12.586 19.414 14 28 5.414 28 12 30 12 30 2 20 2"/>
                </svg>
              </div>
            )}
          </div>
        </div>
        {description && <p className={styles.desc}>{description}</p>}
      </div>
    </El>
  );
};

