// C24dCard.tsx — SCE Design System
// Full-bleed photo card with bottom-up gradient scrim.
// A short yellow rule anchors the title at bottom-left.
// No byline or external-link icon — image and headline only.

import React from 'react';
import styles from './C24dCard.module.css';

export type CardSize = '1col' | '2col' | '3col' | 'mobile';

export interface C24dCardProps {
  /** Full-bleed background image URL. Recommended: ≥1120×480px (2×). */
  src: string;
  /** Alt text for the background photo. Pass "" if title is fully descriptive. */
  alt?: string;
  /** Headline rendered at the bottom-left over the scrim. Keep under ~12 words. */
  title: string;
  /** Column-width token. Maps to 1120 / 548 / 357 / 323 × 240px (120px mobile). */
  size?: CardSize;
  /** Wraps the card in an <a>. Entire card becomes the click target. */
  href?: string;
  className?: string;
}

export const C24dCard: React.FC<C24dCardProps> = ({
  src,
  alt = '',
  title,
  size = '1col',
  href,
  className,
}) => {
  const cls = [styles.card, styles[size], className ?? ''].filter(Boolean).join(' ');

  const inner = (
    <>
      <img className={styles.photo} src={src} alt={alt} aria-hidden={!alt} />
      <div className={styles.scrim} />
      <div className={styles.content}>
        <div className={styles.rule} />
        <p className={styles.title}>{title}</p>
      </div>
    </>
  );

  return href ? (
    <a href={href} className={cls} aria-label={title}>
      {inner}
    </a>
  ) : (
    <div className={cls} role="img" aria-label={title}>
      {inner}
    </div>
  );
};

