// C08QuickActionsBar.tsx — SCE Design System
// Horizontal quick-access bar with 4 SCE utility shortcuts.
// Desktop: horizontal row with 1px dividers between items.
// Mobile: vertical stack, icon above label, compact padding.

import React from 'react';
import styles from './C08QuickActionsBar.module.css';

interface C08Item {
  icon: React.ReactNode;
  label: string;
  sublabel?: string;
  href: string;
}

interface C08QuickActionsBarProps {
  items?: C08Item[];
  variant?: 'desktop' | 'mobile';
}

const defaultItems: C08Item[] = [
  { icon: <PayBillIcon />, label: 'Pay Bill', href: '/billing/pay' },
  { icon: <OutageIcon />,  label: 'Outage',   href: '/outages' },
  { icon: <MovingIcon />,  label: 'Moving',   href: '/start-stop-transfer' },
  { icon: <AssistIcon />,  label: 'Payment Assistance', href: '/assistance' },
];

export function C08QuickActionsBar({
  items = defaultItems,
  variant = 'desktop',
}: C08QuickActionsBarProps) {
  const isVertical = variant === 'mobile';
  return (
    <nav className={styles.bar} aria-label="Quick actions">
      {items.map((item, i) => (
        <a
          key={i}
          href={item.href}
          className={[styles.item, isVertical ? styles.itemVertical : ''].filter(Boolean).join(' ')}
        >
          {item.icon}
          <span className={styles.text}>
            <span className={styles.label}>{item.label}</span>
            {item.sublabel && (
              <span className={styles.sublabel}>{item.sublabel}</span>
            )}
          </span>
        </a>
      ))}
    </nav>
  );
}

