import React from "react";
import { Alert, AlertType } from "./Alert";
import "./MessageStrip.css";

export interface MessageStripItem {
  id: string;
  type: AlertType;
  title: string;
  message: string;
  links?: Array<{ label: string; href: string }>;
  dismissible?: boolean;
}

export interface MessageStripProps {
  items: MessageStripItem[];
  onDismiss?: (id: string) => void;
  showHomeButton?: boolean;
  homeButtonLabel?: string;
  onHomeClick?: () => void;
  className?: string;
}

export const MessageStrip: React.FC<MessageStripProps> = ({
  items,
  onDismiss,
  showHomeButton,
  homeButtonLabel,
  onHomeClick,
  className = "",
}) => {
  if (items.length === 0) return null;

  return (
    <div className={`sce-message-strip ${className}`}>
      {items.map((item) => (
        <Alert
          key={item.id}
          type={item.type}
          title={item.title}
          message={item.message}
          links={item.links}
          showHomeButton={showHomeButton}
          homeButtonLabel={homeButtonLabel}
          onHomeClick={onHomeClick}
          onDismiss={item.dismissible && onDismiss ? () => onDismiss(item.id) : undefined}
          className="sce-message-strip__item"
        />
      ))}
    </div>
  );
};

import React from "react";
import "./Alert.css";

export type AlertType = "error" | "inform" | "warn" | "success" | "pewter";

export interface AlertProps {
  type: AlertType;
  title: string;
  message: string;
  /** Renders a home/back navigation button */
  showHomeButton?: boolean;
  homeButtonLabel?: string;
  onHomeClick?: () => void;
  /** Navigation links rendered below the message */
  links?: Array<{ label: string; href: string }>;
  onDismiss?: () => void;
  className?: string;
}

const ICONS: Record<AlertType, React.ReactNode> = {
  error: (
    <svg width="24" height="24" viewBox="0 0 24 24" aria-hidden="true" fill="currentColor">
      <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z" />
    </svg>
  ),
  inform: (
    <svg width="24" height="24" viewBox="0 0 24 24" aria-hidden="true" fill="currentColor">
      <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z" />
    </svg>
  ),
  warn: (
    <svg width="24" height="24" viewBox="0 0 24 24" aria-hidden="true" fill="currentColor">
      <path d="M1 21h22L12 2 1 21zm12-3h-2v-2h2v2zm0-4h-2v-4h2v4z" />
    </svg>
  ),
  success: (
    <svg width="24" height="24" viewBox="0 0 24 24" aria-hidden="true" fill="currentColor">
      <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-2 14l-5-5 1.41-1.41L10 13.17l7.59-7.59L19 7l-9 9z" />
    </svg>
  ),
  pewter: (
    <svg width="24" height="24" viewBox="0 0 24 24" aria-hidden="true" fill="currentColor">
      <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z" />
    </svg>
  ),
};

export const Alert: React.FC<AlertProps> = ({
  type,
  title,
  message,
  showHomeButton = false,
  homeButtonLabel = "Home",
  onHomeClick,
  links,
  onDismiss,
  className = "",
}) => {
  const roleMap: Record<AlertType, string> = {
    error: "alert",
    warn: "alert",
    inform: "status",
    success: "status",
    pewter: "status",
  };

  return (
    <div
      className={`sce-alert sce-alert--${type} ${className}`}
      role={roleMap[type]}
      aria-live={type === "error" || type === "warn" ? "assertive" : "polite"}
    >
      <div className="sce-alert__icon">{ICONS[type]}</div>

      <div className="sce-alert__body">
        <p className="sce-alert__title">{title}</p>
        <p className="sce-alert__message">{message}</p>

        {links && links.length > 0 && (
          <nav className="sce-alert__links" aria-label="Alert navigation">
            {links.map((link) => (
              <a key={link.href} href={link.href} className="sce-alert__link">
                {link.label}
              </a>
            ))}
          </nav>
        )}

        {showHomeButton && (
          <button
            type="button"
            className="sce-alert__home-btn"
            onClick={onHomeClick}
          >
            {homeButtonLabel}
          </button>
        )}
      </div>

      {onDismiss && (
        <button
          type="button"
          className="sce-alert__dismiss"
          onClick={onDismiss}
          aria-label="Dismiss alert"
        >
          <svg width="24" height="24" viewBox="0 0 24 24" aria-hidden="true" fill="currentColor">
            <path d="M19 6.41L17.59 5 12 10.59 6.41 5 5 6.41 10.59 12 5 17.59 6.41 19 12 13.41 17.59 19 19 17.59 13.41 12z" />
          </svg>
        </button>
      )}
    </div>
  );
};

